import{_ as e,o as d,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt4801.jpg",i="/images/lekt4802.jpg",s="/images/lekt4803.jpg",o="/images/lekt4804.jpg",l="/images/lekt4805.jpg",h="/images/lekt4806.jpg",u="/images/lekt4807.jpg",m="/images/lekt4808.jpg",p="/images/lekt4809.jpg",z=JSON.parse('{"title":"Lektion 48","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion48.md","filePath":"lektionen/lektion48.md"}'),b={name:"lektionen/lektion48.md"};function c(g,t,k,f,q,w){return d(),r("div",null,[...t[0]||(t[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-48" tabindex="-1">Lektion 48 <a class="header-anchor" href="#lektion-48" aria-label="Permalink to &quot;Lektion 48&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>48.1. सुभाषितानि</li><li>48.2. Bildung des Imperativs (लोट्) athematischer Präsensstämme <ul><li>48.2.1. Endungen des Imperativ an athematischen Präsensstämmen</li><li>48.2.2. Form des Präsensstamms</li><li>48.2.3. Zweite Präsensklasse (अदादि)</li><li>48.2.4. Dritte Präsensklasse (जुहोत्यादि)</li></ul></li><li>48.3. Zur Nominalbildung: तद्धित-Suffixe -a und -ya</li><li>48.4. Wortliste</li><li>48.5. Übung</li><li>48.6. Übersetzungsübung</li></ul><h2 id="_48-1-सुभाषितानि" tabindex="-1">48.1. सुभाषितानि <a class="header-anchor" href="#_48-1-सुभाषितानि" aria-label="Permalink to &quot;48.1. सुभाषितानि&quot;">​</a></h2><p>सत्यम् वद ॥१॥</p><p>धर्मं चर ॥२॥</p><p>मातृदेवो भव ॥३॥</p><p>गौरवं प्राप्यते दानात् ॥४॥</p><p>श्वः कार्यमद्य कुर्वीत ॥५॥</p><p>विद्याविहीनः पशुः ॥६॥</p><p>लाघवं वैयाकरणस्य भूषणम् ॥७॥</p><h2 id="_48-2-bildung-des-imperativs-लोट्-athematischer-prasensstamme" tabindex="-1">48.2. Bildung des Imperativs (लोट्) athematischer Präsensstämme <a class="header-anchor" href="#_48-2-bildung-des-imperativs-लोट्-athematischer-prasensstamme" aria-label="Permalink to &quot;48.2. Bildung des Imperativs (लोट्) athematischer Präsensstämme&quot;">​</a></h2><h3 id="_48-2-1-endungen-des-imperativ-an-athematischen-prasensstammen" tabindex="-1">48.2.1. Endungen des Imperativ an athematischen Präsensstämmen <a class="header-anchor" href="#_48-2-1-endungen-des-imperativ-an-athematischen-prasensstammen" aria-label="Permalink to &quot;48.2.1. Endungen des Imperativ an athematischen Präsensstämmen&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>-āni</td><td>-ai</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>-dhi</td><td></td></tr><tr><td>-hi</td><td></td><td></td></tr><tr><td>-ø</td><td></td><td></td></tr><tr><td>-āna</td><td></td><td></td></tr><tr><td>-tāt1</td><td></td><td></td></tr></tbody></table><p>| -sva | -ta | -dhvam | | 3. Person<br> प्रथमः | -tu</p><p>-tāt1</p><p>| -tām | -antu</p><p>3.Kl.: -atu<br> (aus. -*ntu)</p><p>| -atām<br> (aus: -*ntām) |</p><p>Anm.: 1 Die Endungen der 2. und 3.sg.P können durch -tāt ersetzt werden, wenn ein Segenswunsch ausgedrückt werden soll. -tāt tritt (auch in der 3.sg.P) an den schwachen Stamm.</p><table><tbody><tr><td colspan="2">**Zur Form der Endung der 2.sg.Imperativ.P:**</td></tr><tr><td>**-ø**</td><td>**Wurzeln der 5. und 8. Klasse, bei denen dem auslautenden -u nur ein Konsonant vorausgeht.**</td></tr><tr><td>**&lt;nobr&gt;-āna&lt;/nobr&gt;**</td><td>**Wurzeln der 9. Klasse, die auf Konsonant enden, substituieren für -nī+Endung -āna**</td></tr><tr><td>**-hi**</td><td>**alle übrigen Präsensstämme, die auf Vokal oder Halbvokal enden<br>Ausnahme: जुहुधि zu हु 3**</td></tr><tr><td>**-dhi**</td><td>**Alle übrigen Fälle**</td></tr></tbody></table><h3 id="_48-2-2-form-des-prasensstamms" tabindex="-1">48.2.2. Form des Präsensstamms <a class="header-anchor" href="#_48-2-2-form-des-prasensstamms" aria-label="Permalink to &quot;48.2.2. Form des Präsensstamms&quot;">​</a></h3><p>Starker Stamm:</p><ul><li>alle 1. Personen des Imperativ</li><li>3.sg.P Imperativ</li></ul><p>Schwacher Stamm: alle übrigen Formen</p><h3 id="_48-2-3-zweite-prasensklasse-अदादि" tabindex="-1">48.2.3. Zweite Präsensklasse (अदादि) <a class="header-anchor" href="#_48-2-3-zweite-prasensklasse-अदादि" aria-label="Permalink to &quot;48.2.3. Zweite Präsensklasse (अदादि)&quot;">​</a></h3><p>द्विष् 2U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>द्वेषानि</td><td>द्वेषाम</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>द्विड्ढि</td><td></td></tr><tr><td>dviṣ + dhi</td><td></td><td></td></tr><tr><td>द्विष्टात्</td><td></td><td></td></tr></tbody></table><p>| द्विष्ट | द्विक्ष्व<br> dviṣ + sva | द्विड्ढ्वम्<br> dviṣ + dhvam | | 3. Person<br> प्रथमः | द्वेष्टु</p><p>द्विष्टात्</p><p>| द्विषन्तु | द्विष्टाम् | द्विषताम्<br> dviṣ-atām |</p></blockquote><p>आस् 2Ā</p><blockquote><table tabindex="0"><thead><tr><th></th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>1. Person</td><td></td></tr><tr><td>तृतीयः</td><td>आसै</td></tr><tr><td>2. Person</td><td></td></tr><tr><td>मध्यमः</td><td>आस्स्व</td></tr><tr><td>ās + dhvam</td><td></td></tr><tr><td>3. Person</td><td></td></tr><tr><td>प्रथमः</td><td>आस्ताम्</td></tr></tbody></table></blockquote><p>दुह् 2U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>दोहानि</td><td>दोहाम</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>दुग्धि</td><td></td></tr><tr><td>duh + dhi</td><td>दुग्ध</td><td></td></tr><tr><td>duh + ta</td><td>धुक्ष्व</td><td></td></tr><tr><td>duh + sva</td><td>धुग्ध्वम्</td><td></td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>दोग्धु</td><td></td></tr><tr><td>doh + tu</td><td>दुहन्तु</td><td>दुग्धाम्</td></tr></tbody></table></blockquote><p>इ 2P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>1. Person</td><td></td></tr><tr><td>तृतीयः</td><td>अयानि</td></tr><tr><td>e + āni</td><td>अयाम</td></tr><tr><td>2. Person</td><td></td></tr><tr><td>मध्यमः</td><td>इहि</td></tr><tr><td>3. Person</td><td></td></tr><tr><td>प्रथमः</td><td>एतु</td></tr><tr><td>y-antu</td><td></td></tr></tbody></table></blockquote><p>शी 2Ā (immer hochstufig!)</p><blockquote><table tabindex="0"><thead><tr><th></th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>1. Person</td><td></td></tr><tr><td>तृतीयः</td><td>शयै</td></tr><tr><td>śe + ai</td><td>शयामहै</td></tr><tr><td>2. Person</td><td></td></tr><tr><td>मध्यमः</td><td>शेष्व</td></tr><tr><td>3. Person</td><td></td></tr><tr><td>प्रथमः</td><td>शेताम्</td></tr></tbody></table></blockquote><p>हन् 2P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>1. Person</td><td></td></tr><tr><td>तृतीयः</td><td>हनानि</td></tr><tr><td>2. Person</td><td></td></tr><tr><td>मध्यमः</td><td>जहि 1</td></tr><tr><td>aus: *hn-ta</td><td></td></tr><tr><td>3. Person</td><td></td></tr><tr><td>प्रथमः</td><td>हन्तु</td></tr></tbody></table><p>1 Erklärung von जहि siehe Thumb-Hauschild I,2 S. 253</p></blockquote><p>स्तु 2U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>स्तवानि</td><td></td></tr><tr><td>sto + āni</td><td>स्तवाम</td><td>स्तवै</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>स्तुहि</td><td></td></tr><tr><td>स्तुवीहि</td><td>स्तुत</td><td></td></tr><tr><td>स्तुवीत</td><td>स्तुष्व</td><td></td></tr><tr><td>स्तुवीष्व</td><td>स्तुध्वम्</td><td></td></tr><tr><td>स्तुवीध्वम्</td><td></td><td></td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>स्तौतु</td><td></td></tr><tr><td>स्तवीतु</td><td>स्तुवन्तु</td><td>स्तुताम्</td></tr><tr><td>स्तुवीताम्</td><td>स्तुवताम्</td><td></td></tr></tbody></table></blockquote><p>अस् 2P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>1. Person</td><td></td></tr><tr><td>तृतीयः</td><td>असानि</td></tr><tr><td>2. Person</td><td></td></tr><tr><td>मध्यमः</td><td>एधि</td></tr><tr><td>aus: *s-dhi</td><td>स्त</td></tr><tr><td>3. Person</td><td></td></tr><tr><td>प्रथमः</td><td>अस्तु</td></tr></tbody></table></blockquote><p>शास् 2P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>1. Person</td><td></td></tr><tr><td>तृतीयः</td><td>शासानि</td></tr><tr><td>2. Person</td><td></td></tr><tr><td>मध्यमः</td><td>शाधि</td></tr><tr><td>aus: śās + dhi</td><td></td></tr><tr><td>unregelm. hochstufig</td><td>शिष्ट</td></tr><tr><td>3. Person</td><td></td></tr><tr><td>प्रथमः</td><td>शास्तु</td></tr><tr><td>unregelm. hochstufig</td><td></td></tr></tbody></table></blockquote><h3 id="_48-2-4-dritte-prasensklasse-जुहोत्यादि" tabindex="-1">48.2.4. Dritte Präsensklasse (जुहोत्यादि) <a class="header-anchor" href="#_48-2-4-dritte-prasensklasse-जुहोत्यादि" aria-label="Permalink to &quot;48.2.4. Dritte Präsensklasse (जुहोत्यादि)&quot;">​</a></h3><p>Die 3.pl.P endet auf -atu !</p><p>हु 3P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>जुहवानि</td><td></td></tr><tr><td>ju-ho + āni</td><td>जुहवाम</td><td>&lt;जुहवै&gt;</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>जुहुधि</td><td></td></tr><tr><td>unregelmäßig1</td><td>जुहुत</td><td>&lt;जुहुष्व&gt;</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>जुहोतु</td><td>जुह्वतु</td></tr><tr><td>ju-hu + atu</td><td>&lt;जुहुताम्&gt;</td><td>&lt;जुह्वताम्&gt;</td></tr><tr><td></td><td></td><td></td></tr></tbody></table><p>1 Dissimilation, sodass nicht zwei Silben mit ह् aufeinanderfolgen.</p></blockquote><p>धा 3U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>दधानि</td><td></td></tr><tr><td>da-dhā + āni</td><td>दधाम</td><td>दधै</td></tr><tr><td>da-dhā + ai</td><td>दधामहै</td><td></td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>धेहि 1</td><td>धत्त</td></tr><tr><td>da-dh + ta</td><td>धत्स्व</td><td>धद्ध्वम्</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>दधातु</td><td>दधतु</td></tr><tr><td>da-dh-atu</td><td>धत्ताम्</td><td>दधताम्</td></tr></tbody></table><p>1 धेहि aus *dhazdhi: Wegfall des indogermanischen Zischlauts z unter Ersatzdehnung ; s. Thumb-Hauschild I,1 S. 302</p></blockquote><p>हा 3P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>1. Person</td><td></td></tr><tr><td>तृतीयः</td><td>जहानि</td></tr><tr><td>2. Person</td><td></td></tr><tr><td>मध्यमः</td><td>जहाहि</td></tr><tr><td>unregelm. stark. St.</td><td></td></tr><tr><td>जहीहि</td><td></td></tr><tr><td>जहिहि</td><td>जहीत</td></tr><tr><td>जहित</td><td></td></tr><tr><td>3. Person</td><td></td></tr><tr><td>प्रथमः</td><td>जहातु</td></tr><tr><td>ja-h-atu</td><td></td></tr></tbody></table></blockquote><h2 id="_48-3-zur-nominalbildung-तद्धित-suffixe-a-und-ya" tabindex="-1">48.3. Zur Nominalbildung: तद्धित-Suffixe -a und -ya <a class="header-anchor" href="#_48-3-zur-nominalbildung-तद्धित-suffixe-a-und-ya" aria-label="Permalink to &quot;48.3. Zur Nominalbildung: तद्धित-Suffixe -a und -ya&quot;">​</a></h2><p>Mit dem Suffix -a und (seltener) -ya kann aus einem Nomen ein anderes Nomen abgeleitet werde. Dabei erhält die erste Silbe des ursprünglichen Nomens Dehnstufe (वृद्धि). Endet der ursprüngliche Wortstamm bereits auf -a so ist die वृद्धि das einzige Zeichen der Ableitung, da sich am Stammauslaut nichts ändert.</p><p>Die abgeleitenden Wörter haben die Bedeutung:</p><p>&quot;irgendeine Beziehung zu dem durch das Grundwort Bezeichnete habend&quot;</p><p>z.B.</p><ul><li><p>&quot;stammend von&quot;</p></li><li><p>&quot;gehörig zu&quot;</p></li></ul><p>Die so gebildeten Wörter sind Adjektive, können aber substantiviert werden, z.B. als Patronymica (Namensbildung nach dem Vater: &quot;Sohn des N.N:&quot;) oder Abstrakta (meist Neutra).</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Grundwort</th><th>Ableitung</th></tr></thead><tbody><tr><td>शुचि 3 &quot;leuchtend, rein&quot;</td><td>शौच n. &quot;Reinheit&quot;</td></tr><tr><td>पुत्र m. &quot;Sohn&quot;</td><td>पौत्र m. &quot;vom Sohn stammend = Sohnessohn, Enkel&quot;</td></tr><tr><td>गोतम m. &quot;Besitzer sehr vieler Rinder&quot; Eigenname</td><td>गौतम m. &quot;Sohn des Gotama&quot;</td></tr><tr><td>ब्रह्मन् n. &quot;formulierte Wahrheit, Veda, Absolutes&quot;</td><td>ब्राह्मण m. &quot;Wahrheitsformulierer, Brahmane&quot;</td></tr><tr><td>शूर 3 &quot;heldenhaft&quot;</td><td>शौर्य n. &quot;Heldenhaftigkeit, Tapferkeit&quot;</td></tr><tr><td>राजन् m. &quot;König&quot;</td><td>राज्य n. &quot;Königsherrschaft&quot;</td></tr><tr><td>देव m. &quot;Himmlischer, Gott&quot;</td><td>दैव्य 3 &quot;himmlisch&quot;</td></tr><tr><td>ग्राम m. &quot;Dorf&quot;</td><td>ग्राम्य 3 &quot;dörfisch&quot;</td></tr></tbody></table></blockquote><table><tbody><tr><td colspan="2">**Behandlung des Stammauslautes vor dem Suffix -a:**</td></tr><tr><td>**Stämme auf:**</td><td></td></tr><tr><td>**-ṛ**</td><td>**-a tritt in der Regel an den Auslaut -r:**&lt;blockquote&gt;z.B. जेतृ &quot;Sieger&quot; » जैत्र 3 &quot;siegreich&quot;<br>&lt;/blockquote&gt;</td></tr><tr><td>**-a**</td><td>**Ersatz des -a des Grundwortes durch das neue Suffix -a.**Beispiele siehe oben.</td></tr><tr><td>**-i**</td><td>**Wegfall des -i**&lt;blockquote&gt;z.B. प्रकृति f. &quot;Natur&quot; » प्राकृत 3 &quot;natürlich, normal, üblich, vulgär&quot;<br>&lt;/blockquote&gt;</td></tr><tr><td>**-u**</td><td>**meistens: -av-a**&lt;blockquote&gt;z.B. गुरु 3 &quot;schwer&quot; ; m. &quot;Meister, Lehrer&quot; » गौरव 3 &quot;zum Meister gehörig, vom Meister stammend&quot; ; n. &quot;Gewicht, Schwere, Würde&quot;<br>&lt;/blockquote&gt;</td></tr><tr><td colspan="2">**andere Deklinationsstämme: s. Wackernagel, Altind. Grammatik II,2 § 38**</td></tr></tbody></table><p>Vor dem Suffix -ya wird der Stammauslaut ähnlich wie vor dem Suffix -a behandelt.</p><blockquote><p>Beispiele siehe oben!</p></blockquote><p>Mittels dieser Suffixe können auch von Komposita Ableitungen gebildet werden.</p><blockquote><p>z.B. स्वश्व m. &quot;der, dessen Pferde gut sind&quot; Eigenname » सौवश्व m. &quot;Nachkomme des Svaśva&quot;</p></blockquote><p>Bei Komposita, in denen infolge des Sandhi im Vorderglied auslautendes -i oder -u durch -y bzw. -v ersetzt werden und so dem ersten Vokal des Grundwortes vorausgehen (z.B. Komposita mit ni-, vi-, su-), wird die वृद्धि so gebildet, als ob -iy bzw. -uv datsehen würde.</p><blockquote><p>z.B. व्याघ्र m. &quot;Tiger&quot; » वैयाघ्र 3. &quot;von einem Tiger stammend, zu einem Tiger gehörend&quot;</p></blockquote><p><img src="'+n+'" alt=""><br> Abb.: वैयाघ्रं विजृम्भणम् (Gähnen)<br> [Bildquelle: Gunnlaugur Þ. Briem. -- <a href="http://www.flickr.com/photos/gthb/247964428/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/gthb/247964428/</a>. -- Zugriff am 2009-01-10. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><h2 id="_48-4-wortliste" tabindex="-1">48.4. Wortliste <a class="header-anchor" href="#_48-4-wortliste" aria-label="Permalink to &quot;48.4. Wortliste&quot;">​</a></h2><p>श्वस् : morgen</p><p>अद्य : heute</p><p>लघु 3: leicht (nicht schwer, nicht schwierig), schnell, kurz (im Ausdruck)</p><p>व्याकरण n.: Grammatik (zu व्याकृ)</p><p>तन्त्र n.: Saite ; Webstuhl, Webkette, Gewebe ; Grundlage, Norm, Regel ; Lehre, Lehrwerk ; Tantra ; Zauberformel ; Mittel, Trick, Arzneimittel ; Regierung, Autorität</p><p><img src="'+i+'" alt=""><br> Abb.: तन्त्रम्<br> Sualkuchi = সুৱালকুচি, Assam = অসম<br> [Bildquelle: Ken McChesney. -- <a href="http://www.flickr.com/photos/kenmak/2083565996/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/kenmak/2083565996/</a>. -- Zugriff am 2009-01-10. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p><img src="'+s+'" alt=""><br> Abb.: तन्त्री<br> Sitarspieler = सितारवादकः<br> [Bildquelle: Wikipedia. Public domain]</p><p>स्त्री f.: Frau, Gattin ; Femininum</p><blockquote><p>Deklination:</p><table tabindex="0"><thead><tr><th></th><th>एकवचनम</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा</td><td>स्त्री</td><td>स्त्रियस्</td></tr><tr><td>द्वितीया</td><td>स्त्रियम्</td><td></td></tr><tr><td>स्त्रीयम्</td><td>स्त्रियस्</td><td></td></tr><tr><td>स्त्रीस्</td><td></td><td></td></tr><tr><td>तृतीया</td><td>स्त्रिया</td><td>स्त्रीभिस्</td></tr><tr><td>चतुर्थी</td><td>स्त्रियै</td><td>स्त्रीभ्यस्</td></tr><tr><td>पञ्चमी</td><td>स्त्रियास्</td><td>स्त्रीभ्यस्</td></tr><tr><td>षष्ठी</td><td>स्त्रियास्</td><td>स्त्रीणाम्</td></tr><tr><td>सप्तमी</td><td>स्त्रियाम्</td><td>स्त्रीषु</td></tr><tr><td>आमन्त्रितम्</td><td>स्त्रि</td><td>स्त्रियस्</td></tr></tbody></table></blockquote><p><img src="'+o+'" alt=""><br> Abb.: स्वतन्त्राः स्त्रियः<br><a href="http://en.wikipedia.org/wiki/Self-help_group_(finance)" target="_blank" rel="noreferrer">Self-help group (SHG)</a>, Tamil Nadu = தமிழ்நாடு<br> [Bildquelle: mckaysavage. -- <a href="http://www.flickr.com/photos/mckaysavage/2229752965/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mckaysavage/2229752965/</a>. -- Zugriff am 2009-01-10. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>दिवानिशम् Adverb: bei Tag und Nacht</p><p>सज्ज् 1P सज्जति : hängen, anhaften</p><p>कुमार m.: Kind, Jüngling, Prinz; Beiname des कार्तिकेय / Murugan = முருகன் = മുരുകന്‍ / Subrahmanya = ಸುಬ್ರಹ್ಮಣ್ಯ</p><p><img src="'+l+'" alt=""><br> Abb.: कुमारः / Murugan = முருகன்<br> Thaipusam-Fest = தைப்பூசம், Batu Caves, Malaysia<br> [Bildquelle: tajai. -- <a href="http://www.flickr.com/photos/cayce/108707865/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/cayce/108707865/</a>. -- Zugriff am 2009-01-10. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>कुमारी f.: Mädchen, Tochter</p><p><img src="'+h+'" alt=""><br> Abb.: <a href="http://en.wikipedia.org/wiki/Kumari" target="_blank" rel="noreferrer">कुमारी</a><br> नेपाल<br> [Bildquelle: changhg. -- <a href="http://www.flickr.com/photos/changhg/100412648/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/changhg/100412648/</a>. -- Zugriff am 2009-01-10. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>कौमर n.: Kindheit</p><p>यौवन n.: Jugend</p><p>स्थविर 3: alt, betagt</p><p><img src="'+u+'" alt=""><br> Abb.: स्थविराः<br> जोधपुर<br> [Bildquelle: zz77. -- <a href="http://www.flickr.com/photos/zz77/2256414024/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/zz77/2256414024/</a>. -- Zugriff am 2009-01-10. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>स्थाविर n.: (hohes) Alter</p><p>वाच्य 3: auch: tadelnswert</p><p>सूक्ष्म 3: fein, winzig, subtil</p><p><img src="'+m+'" alt=""><br> Abb.: सूक्ष्मम्<br> Karanji Lake = ಕಾರಂಜಿ ಕೆರೆ<br> [Bildquelle: Nagesh Kamath. -- <a href="http://www.flickr.com/photos/nagesh_kamath/2791791571/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/nagesh_kamath/2791791571/</a>. -- Zugriff am 2009-01-10. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, share alike)]</p><p>प्रसङ्ग m.:  Anhaftung, Neigung ; Gelegenheit</p><p>विशेष m.: Unterschied, Besonderheit</p><p>प्रसूति f.: Geburt, Nachkommenschaft</p><p>चरित्र n.: Brauch, Sitte, Gewohnheitsrecht ; Wandel</p><p>जाया f.: Ehefrau</p><p><img src="'+p+'" alt=""><br> Abb.: मम जाया<br> (Bild: Payer)</p><h2 id="_48-5-ubung" tabindex="-1">48.5. Übung <a class="header-anchor" href="#_48-5-ubung" aria-label="Permalink to &quot;48.5. Übung&quot;">​</a></h2><p>A) Übersetzen Sie die सुभाषितानि zu Beginn der Lektion.</p><p>B) Übersetzen Sie ins Sanskrit (verwenden Sie dabei den Imperativ und möglichst Wurzeln der 2. und 3. Präsensklasse):</p><p>1. Nachdem du einen Sohn bekommen hast, verlasse die Familie!</p><p>2. Nachkommen des Puru, fürchtet euch vor denen, die Böses getan haben!</p><p>3. Die Mädchen sollen den Bettlern Speise geben.</p><p>4. Wir wollen sprechen.</p><p>5. Mit den Worten &quot;Komm Mönch!&quot; nahm Buddha den Mann in den Mönchsorden auf (उपसम्पद् Kausativ).</p><p>6. Seid wahre Nachfahren Manus!</p><p>7. Ich will शिव und die anderen Götter preisen.</p><p>8. Erzähle!</p><p>9. Miss die Höllen aus!</p><p>10. Sie (pl.) sollen auf diesen Liegen liegen.</p><p>11. Die tigergleichen Männer sollen die töten, die Indra feind sind.</p><p>12. Konzentriere dich!</p><p>13. Sitzt hier!</p><p>14. Wir wollen diese Früchte essen.</p><p>15. Der Diener soll die Kuh melken.</p><p>16. König, hüte den Dharma und die Leute.</p><p>17. Lehre die Schüler den Veda!</p><p>18. Er soll neue Kleider anziehen.</p><p>19. Sie (pl.) sollen in meinem Haus sitzen.</p><p>20. Ehemänner sollen ihre Gattinnen erhalten (i. S. v. Unterhalt).</p><h2 id="_48-6-ubersetzungsubung" tabindex="-1">48.6. Übersetzungsübung <a class="header-anchor" href="#_48-6-ubersetzungsubung" aria-label="Permalink to &quot;48.6. Übersetzungsübung&quot;">​</a></h2><p>मनुस्मृति ९ (स्त्रीधर्मः):</p><blockquote><p>अस्वतन्त्राः स्त्रियः कार्याः पुरुषैः स्वैर्दिवानिशम् ।<br> विषयेषु च सज्जन्त्यः संस्थाप्या आत्मनो वशे ॥२॥<br> पिता र्क्षति कौमरे भर्ता रक्षति यौवने ।<br> रक्षन्ति स्थाविरे पुत्रा न स्त्री स्वातन्त्र्यमर्हति ॥३॥<br> काले ऽदाता पिता वाच्यो वाच्यश्चानुपनयन्पतिः ।<br> मृते भर्तरि पुत्रस्तु वाच्यो मातुररक्षिता ॥४॥<br> सूक्ष्मेभ्यो ऽपि प्रसङ्गेभ्यः स्त्रियो रक्ष्या विशेषतः ।<br> द्वयोर्हि कुलयोः शोकमावहेयुररक्षिताः ॥५॥<br> इमं हि सर्ववर्णानां पश्यन्तो धर्ममुत्तमम् ।<br> यतन्ते रक्षितुं भार्यां भर्तारो दुर्बला अपि ॥६॥<br> स्वां प्रसूतिं चरित्रं च कुलमात्मानमेव च ।<br> स्वं च धर्मं प्रयत्नेन जायां रक्षन्हि रक्षति ॥७॥<br> पतिर्भार्यां संप्रविश्य गर्भो भूत्वेह जायते ।<br> जायायास्तद्धि जायात्वं यद् अस्यां जायते पुनः ॥८॥</p><p>Erklärung:<br> द्वयोर्हि कुलयोः : Gen. (षष्ठी) Dual zu द्वे कुले &quot;zwei Familien&quot;</p></blockquote>',127)])])}const _=e(b,[["render",c]]);export{z as __pageData,_ as default};
